+func TestDetermineOverallHealth(t *testing.T) {
+	tests := []struct {
+		name    string
+		summary DiagnoseSummary
+		want    string
+	}{
+		// Healthy cases
+		{
+			name: "all healthy",
+			summary: DiagnoseSummary{
+				TotalPanes: 4,
+				Healthy:    4,
+			},
+			want: "healthy",
+		},
+		{
+			name: "empty session",
+			summary: DiagnoseSummary{
+				TotalPanes: 0,
+			},
+			want: "healthy",
+		},
+		{
+			name: "single healthy pane",
+			summary: DiagnoseSummary{
+				TotalPanes: 1,
+				Healthy:    1,
+			},
+			want: "healthy",
+		},
+
+		// Degraded cases
+		{
+			name: "one rate limited",
+			summary: DiagnoseSummary{
+				TotalPanes:  4,
+				Healthy:     3,
+				RateLimited: 1,
+			},
+			want: "degraded",
+		},
+		{
+			name: "one unresponsive minority",
+			summary: DiagnoseSummary{
+				TotalPanes:   4,
+				Healthy:      3,
+				Unresponsive: 1,
+			},
+			want: "degraded",
+		},
+		{
+			name: "one unknown",
+			summary: DiagnoseSummary{
+				TotalPanes: 4,
+				Healthy:    3,
+				Unknown:    1,
+			},
+			want: "degraded",
+		},
+		{
+			name: "multiple degraded states",
+			summary: DiagnoseSummary{
+				TotalPanes:   8,
+				Healthy:      5,
+				RateLimited:  2,
+				Unresponsive: 1,
+			},
+			want: "degraded",
+		},
+
+		// Critical cases
+		{
+			name: "any crashed pane",
+			summary: DiagnoseSummary{
+				TotalPanes: 4,
+				Healthy:    3,
+				Crashed:    1,
+			},
+			want: "critical",
+		},
+		{
+			name: "majority unresponsive",
+			summary: DiagnoseSummary{
+				TotalPanes:   4,
+				Healthy:      1,
+				Unresponsive: 3,
+			},
+			want: "critical",
+		},
+		{
+			name: "equal unresponsive and healthy",
+			summary: DiagnoseSummary{
+				TotalPanes:   4,
+				Healthy:      2,
+				Unresponsive: 2,
+			},
+			want: "degraded", // Not majority, so degraded not critical
+		},
+		{
+			name: "multiple crashed",
+			summary: DiagnoseSummary{
+				TotalPanes: 4,
+				Healthy:    2,
+				Crashed:    2,
+			},
+			want: "critical",
+		},
+		{
+			name: "crashed plus rate limited",
+			summary: DiagnoseSummary{
+				TotalPanes:  4,
+				Healthy:     2,
+				Crashed:     1,
+				RateLimited: 1,
+			},
+			want: "critical",
+		},
+	}
+
+	for _, tt := range tests {
+		t.Run(tt.name, func(t *testing.T) {
+			got := determineOverallHealth(tt.summary)
+			if got != tt.want {
+				t.Errorf("determineOverallHealth(%+v) = %q, want %q", tt.summary, got, tt.want)
+			}
+		})
+	}
+}
