+	Findings    []UBSFinding `json:"findings,omitempty"`
+	TotalCount  int          `json:"total_count"`
+	Critical    int          `json:"critical"`
+	High        int          `json:"high"`
+	Medium      int          `json:"medium"`
+	Low         int          `json:"low"`
+	Info        int          `json:"info"`
+	ScanTime    string       `json:"scan_time,omitempty"`
